const keyResp = $json;
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY || '';

async function fetchPipelineSecret(keyName) {
  try {
    return await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/functions/v1/get-pipeline-secret',
      headers: { apikey: SUPABASE_KEY, Authorization: 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' },
      body: { keyName },
      json: true
    });
  } catch (e) { return null; }
}

if (keyResp && keyResp.value) {
  const key = String(keyResp.value).trim();
  if (key) return [{ json: { api_key: key, source: 'db', provider: 'claude' } }];
}

const secret = await fetchPipelineSecret.call(this, 'ANTHROPIC_API_KEY');
if (secret && secret.value) {
  const key = String(secret.value).trim();
  if (key) return [{ json: { api_key: key, source: 'db:ANTHROPIC_API_KEY', provider: 'claude' } }];
}

const envKey = $env.ANTHROPIC_API_KEY || '';
if (envKey && envKey.length > 5) return [{ json: { api_key: envKey, source: 'env', provider: 'claude' } }];

throw new Error('ANTHROPIC_API_KEY não encontrada em DB ou env. Configure em Automações > Configurações.');

const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY || '';
const headers = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };

const topicMap = {
  'ia': 'Inteligencia Artificial', 'tecnologia': 'Tecnologia',
  'ciberseguranca': 'Ciberseguranca', 'automacao': 'Automacao',
  'mundo': 'Mundo', 'saude': 'Saude', 'musica': 'Musica',
  'desporto': 'Desporto', 'geral': 'Tecnologia'
};

// ── 1. Ler fila de links pendentes (mais antigos primeiro) ─────────────────
let pendingItem = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/article_link_graph?select=id,target_slug,href,anchor_text,created_at' +
      '&status=eq.pending' +
      '&order=created_at.asc&limit=1',
    headers, json: true
  });
  if (Array.isArray(resp) && resp.length > 0) pendingItem = resp[0];
} catch (e) { /* non-fatal */ }

// ── 2. Ler clusters de notícias disponíveis ────────────────────────────────
let newsCluster = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/news_clusters' +
      '?select=id,topic,fingerprint,source_count,confidence_score,trend_score,priority_rank,search_volume' +
      '&confidence_score=gte.60&is_curated=not.is.true' +
      '&order=priority_rank.desc.nullslast,confidence_score.desc&limit=1',
    headers, json: true
  });
  if (Array.isArray(resp) && resp.length > 0) newsCluster = resp[0];
} catch (e) { /* non-fatal */ }

// ── 3. Lógica de prioridade ────────────────────────────────────────────────
let pendingCount = 0;
if (pendingItem) {
  try {
    const countResp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + '/rest/v1/article_link_graph?select=id&status=eq.pending&limit=10',
      headers, json: true
    });
    pendingCount = Array.isArray(countResp) ? countResp.length : 0;
  } catch (e) { /* use 0 */ }
}

let mode = 'news';
if (!newsCluster && !pendingItem) {
  console.log('[WF-03] Smart Route: sem clusters e sem pendentes. A terminar.');
  return [];
} else if (!newsCluster && pendingItem) {
  mode = 'pending';
} else if (newsCluster && !pendingItem) {
  mode = 'news';
} else {
  const pendingAge = pendingItem ? Date.now() - new Date(pendingItem.created_at).getTime() : 0;
  const DEBT_AGE_THRESHOLD_MS = 48 * 60 * 60 * 1000;
  if (pendingAge >= DEBT_AGE_THRESHOLD_MS || pendingCount >= 3) {
    mode = 'pending';
  } else {
    mode = 'news';
  }
}

console.log('[WF-03] Smart Route: modo=' + mode + ' | pendentes=' + pendingCount);

// ── 4. Modo NEWS ──────────────────────────────────────────────────────────
if (mode === 'news' && newsCluster) {
  return [{ json: {
    _mode: 'news',
    id: newsCluster.id,
    topic: newsCluster.topic,
    fingerprint: newsCluster.fingerprint,
    source_count: newsCluster.source_count,
    confidence_score: newsCluster.confidence_score,
    trend_score: newsCluster.trend_score || 0,
    priority_rank: newsCluster.priority_rank || 0,
    search_volume: newsCluster.search_volume || 0,
    pending_link_id: null
  }}];
}

// ── 5. Modo PENDING ───────────────────────────────────────────────────────
if (mode === 'pending' && pendingItem) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: SUPABASE_URL + '/rest/v1/article_link_graph?id=eq.' + pendingItem.id + '&status=eq.pending',
      headers: { ...headers, 'Prefer': 'return=minimal' },
      body: { status: 'generating', locked_at: new Date().toISOString() },
      json: true
    });
  } catch (e) { /* non-fatal */ }

  const hrefParts = (pendingItem.href || '').split('/').filter(Boolean);
  const rawTopic = hrefParts.length >= 2 ? hrefParts[0] : 'tecnologia';
  const topic = Object.keys(topicMap).find(k => rawTopic.includes(k)) || rawTopic;
  const topicLabel = topicMap[topic] || rawTopic;

  const stopWords = new Set(['para', 'como', 'que', 'dos', 'das', 'nos', 'nas', 'com', 'por', 'uma', 'uns', 'umas']);
  const slugWords = (hrefParts[hrefParts.length - 1] || pendingItem.target_slug || '')
    .replace(/-/g, ' ').split(/\s+/)
    .filter(w => w.length > 3 && !stopWords.has(w));
  const anchorWords = (pendingItem.anchor_text || '')
    .split(/\s+/).filter(w => w.length > 3 && !stopWords.has(w));
  const inferred_keywords = [...new Set([...anchorWords.slice(0, 2), ...slugWords.slice(0, 3)])].slice(0, 4);

  return [{ json: {
    _mode: 'pending',
    id: null,
    pending_link_id: pendingItem.id,
    topic,
    topic_label: topicLabel,
    fingerprint: null,
    source_count: 0,
    confidence_score: 72,
    trend_score: 65,
    priority_rank: 95,
    search_volume: 0,
    target_slug: pendingItem.target_slug || hrefParts[hrefParts.length - 1],
    href: pendingItem.href,
    anchor_text: pendingItem.anchor_text || '',
    inferred_keywords
  }}];
}

return [];

const route = $('Smart Route: Pending vs News').first().json;
