const prev = $('Build AI Prompt + SEO').first().json;
const keyData = $('Validate Key').first().json;
const apiKey = keyData.api_key;

async function callClaude(prompt, key) {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': key,
      'anthropic-version': '2023-06-01',
      'anthropic-beta': 'prompt-caching-2024-07-31',
      'Content-Type': 'application/json'
    },
    body: {
      model: 'claude-sonnet-4-6',
      max_tokens: 6000,
      system: [{ type: 'text', text: 'És o Motor Editorial Vision7. Escreves em Português Europeu (PT-PT). Estilo analítico, preciso, orientado para dados. Nunca genérico. Nunca clichés. Cada artigo tem valor informativo real para profissionais portugueses. Respondes SEMPRE em JSON válido com o schema exacto solicitado — sem texto antes ou depois do JSON.', cache_control: { type: 'ephemeral' } }],
      messages: [{ role: 'user', content: prompt }]
    },
    json: true,
    timeout: 120000
  });
  const text = response?.content?.[0]?.text || '';
  return { choices: [{ message: { content: text } }], provider: 'claude', model: 'claude-sonnet-4-6' };
}

try {
