  return [{ json: response }];
} catch (e) {
  const errDetail = e.httpCode ? ' [HTTP ' + e.httpCode + ']' : '';
  return [{ json: { error: { message: e.message + errDetail }, choices: [], provider: 'claude' } }];
}

function mdToHtml(md) {
  if (!md) return '';
  let h = md;
  h = h.replace(/```(\w*)\n([\s\S]*?)```/g, (m, l, c) => '<pre><code>' + c.replace(/</g, '&lt;').replace(/>/g, '&gt;').trimEnd() + '</code></pre>');
  h = h.replace(/`([^`]+)`/g, '<code>$1</code>');
  h = h.replace(/!\[([^\]]*)\]\(([^)]+)\)/g, '<img src="$2" alt="$1" loading="lazy" />');
  h = h.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
  h = h.replace(/^######\s+(.+)$/gm, '<h6>$1</h6>');
  h = h.replace(/^#####\s+(.+)$/gm, '<h5>$1</h5>');
  h = h.replace(/^####\s+(.+)$/gm, '<h4>$1</h4>');
  h = h.replace(/^###\s+(.+)$/gm, '<h3>$1</h3>');
  h = h.replace(/^##\s+(.+)$/gm, '<h2>$1</h2>');
  h = h.replace(/^#\s+(.+)$/gm, '<h1>$1</h1>');
  h = h.replace(/^[-*_]{3,}\s*$/gm, '<hr />');
  h = h.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
  h = h.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  h = h.replace(/\*(.+?)\*/g, '<em>$1</em>');
  h = h.replace(/^>\s+(.+)$/gm, '<blockquote><p>$1</p></blockquote>');
  h = h.replace(/(^[\t ]*[-*]\s+.+\n?)+/gm, (block) => {
    const items = block.trim().split('\n').map(l => l.replace(/^[\t ]*[-*]\s+/, '').trim()).filter(Boolean).map(i => '<li>' + i + '</li>').join('\n');
    return '<ul>\n' + items + '\n</ul>';
  });
  h = h.replace(/(^\d+\.\s+.+\n?)+/gm, (block) => {
    const items = block.trim().split('\n').map(l => l.replace(/^\d+\.\s+/, '').trim()).filter(Boolean).map(i => '<li>' + i + '</li>').join('\n');
    return '<ol>\n' + items + '\n</ol>';
  });
  const lines = h.split('\n'); const result = []; let buf = [];
  const isBlock = l => /^<(h[1-6]|ul|ol|li|pre|blockquote|hr|img)\b/i.test(l.trim()) || /^<\/(ul|ol|pre|blockquote)>/i.test(l.trim());
  for (const line of lines) {
    if (line.trim() === '') { if (buf.length) { result.push('<p>' + buf.join(' ') + '</p>'); buf = []; } }
    else if (isBlock(line)) { if (buf.length) { result.push('<p>' + buf.join(' ') + '</p>'); buf = []; } result.push(line); }
    else { buf.push(line.trim()); }
  }
  if (buf.length) result.push('<p>' + buf.join(' ') + '</p>');
  return result.join('\n');
}
