function extractField(text, field) {
  const re = new RegExp('"' + field + '"\\s*:\\s*"');
  const m = re.exec(text);
  if (!m) return '';
  let start = m.index + m[0].length;
  let result = '';
  for (let i = start; i < text.length; i++) {
    if (text[i] === '\\') { result += text[i] + (text[i+1]||''); i++; continue; }
    if (text[i] === '"') { const after = text.substring(i+1).trimStart(); if (after[0] === ',' || after[0] === '}') break; result += text[i]; continue; }
    result += text[i];
  }
  return result.replace(/\n/g, ' ').replace(/\r/g, '').replace(/\t/g, ' ');
}

let article;
try {
  let content = response.choices[0].message.content;
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  try { article = JSON.parse(content); } catch (e1) {
    try {
      let fixed = ''; let inStr = false; let esc = false;
      for (let i = 0; i < content.length; i++) {
        const ch = content[i];
        if (esc) { fixed += ch; esc = false; continue; }
        if (ch === '\\') { fixed += ch; esc = true; continue; }
        if (ch === '"') { inStr = !inStr; fixed += ch; continue; }
        if (inStr && ch === '\n') { fixed += '\\n'; continue; }
        if (inStr && ch === '\r') { fixed += '\\r'; continue; }
        if (inStr && ch === '\t') { fixed += '\\t'; continue; }
        fixed += ch;
      }
      article = JSON.parse(fixed);
    } catch (e2) {
      if (article && article.article) {
        article = article.article;
      } else {
        article = {
          title: extractField(content, 'title'), subtitle: extractField(content, 'subtitle'),
          excerpt: extractField(content, 'excerpt'), body_markdown: extractField(content, 'body_markdown'),
          topic: extractField(content, 'topic') || prev.topic,
          primary_keyword: extractField(content, 'primary_keyword'),
          meta_description: extractField(content, 'meta_description'),
          search_intent: extractField(content, 'search_intent') || 'informational'
        };
      }
      if (!article.title || article.title.length < 5) throw new Error('All parse strategies failed');
    }
  }
  if (article.article) article = article.article;
} catch (e) {
  return [{ json: { error: 'Failed to parse AI response: ' + e.message, cluster_id: prev.cluster_id, skip: true } }];
}

const body = article.body_markdown || '';
const title = article.title || '';
const pk = article.primary_keyword || '';
const sourceTitles = (prev.source_articles || []).map(s => (s.title || '').toLowerCase());

let seoScore = 0;
if (pk) {
  seoScore += 20;
  if (title.toLowerCase().includes(pk.toLowerCase())) seoScore += 20;
  if (body.substring(0, 150).toLowerCase().includes(pk.toLowerCase())) seoScore += 15;
  if ((article.meta_description || '').toLowerCase().includes(pk.toLowerCase())) seoScore += 15;
  const pkCount = (body.toLowerCase().match(new RegExp(pk.toLowerCase().replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'g')) || []).length;
  if (pkCount >= 2 && pkCount <= 8) seoScore += 15; else if (pkCount >= 1) seoScore += 8;
  if (article.secondary_keywords && article.secondary_keywords.length >= 2) seoScore += 15;
}
if ((article.meta_description || '').length >= 50 && (article.meta_description || '').length <= 160) seoScore = Math.min(seoScore + 10, 100);

const sentences = body.split(/[.!?]+/).filter(s => s.trim().length > 3);
const words = body.split(/\s+/).filter(w => w.length > 0);
const avgWordsPerSentence = sentences.length > 0 ? words.length / sentences.length : 0;
let readabilityScore = 60;
if (avgWordsPerSentence > 5 && avgWordsPerSentence < 25) readabilityScore += 15;
else if (avgWordsPerSentence >= 25 && avgWordsPerSentence < 35) readabilityScore += 5;
else readabilityScore -= 15;
const paragraphs = body.split(/\n\n+/).filter(p => p.trim().length > 10);
if (paragraphs.length >= 3) readabilityScore += 10;
const h2Count = (body.match(/^## /gm) || []).length;
const h3Count = (body.match(/^### /gm) || []).length;
if (h2Count >= 2) readabilityScore += 10; else if (h2Count >= 1) readabilityScore += 5;
if (h3Count >= 1) readabilityScore += 5;
if (body.includes('**') || body.includes('*')) readabilityScore += 5;
if ((body.match(/^[-*] /gm) || []).length >= 2) readabilityScore += 5;
readabilityScore = Math.max(0, Math.min(readabilityScore, 100));

const titleWords = title.toLowerCase().split(/\s+/).filter(w => w.length > 3);
let commonWithSources = 0;
for (const sw of sourceTitles) {
  const sourceWords = sw.split(/\s+/).filter(w => w.length > 3);
  for (const tw of titleWords) { if (sourceWords.includes(tw)) commonWithSources++; }
}
const titleOverlap = titleWords.length > 0 ? commonWithSources / titleWords.length : 0;
let originalityScore = Math.max(20, Math.min(100 - Math.round(titleOverlap * 60), 100));

const hasToc = /##\s*(Índice|Table of Contents|Indice)/i.test(body) || (body.match(/\[.+\]\(#.+\)/g) || []).length >= 3;
const hasPortugalSection = /##\s*.*Portugal/i.test(body) || Boolean(article.portugal_section && Object.keys(article.portugal_section).length >= 1);
const hasFaq = h3Count >= 2;
const hasDatedPrediction = /até (janeiro|fevereiro|março|abril|maio|junho|julho|agosto|setembro|outubro|novembro|dezembro|\d{4})/i.test(body) || Boolean(article.dated_prediction && article.dated_prediction.length > 5);
const hasFrameworkVisual = (body.match(/\|.+\|/g) || []).length >= 3 || /ÍNDICE VISION7|Timeline|Matriz/i.test(body);
const hasCta = /##\s*(Conclus|CTA|Call to Action|Próximos Passos)/i.test(body) || Boolean(article.cta && article.cta.length > 10);
const hasMinWords = words.length >= 1000;

const audit = {
  has_title: Boolean(title && title.length > 10),
  has_body: Boolean(body && body.length > 500),
  has_excerpt: Boolean(article.excerpt && article.excerpt.length > 20),
  has_headings: h2Count >= 5,
  has_toc: hasToc,
  has_portugal_section: hasPortugalSection,
  has_faq: hasFaq,
  has_dated_prediction: hasDatedPrediction,
  has_framework_visual: hasFrameworkVisual,
  has_cta: hasCta,
  has_min_words: hasMinWords,
  has_references: /##\s*(Fontes|Refer[eê]ncias)/i.test(body) || (body.match(/https?:\/\//g) || []).length >= 2,
  body_length: body.length,
  word_count: words.length,
  heading_count: h2Count + h3Count,
  language_ok: /[a-zA-Z]/.test(body),
  has_primary_keyword: Boolean(pk),
  has_meta_description: Boolean(article.meta_description && article.meta_description.length >= 30),
  seo_score: seoScore,
  readability_score: readabilityScore,
  originality_score: originalityScore
};

const boolChecks = Object.entries(audit).filter(([k, v]) => typeof v === 'boolean');
const passedChecks = boolChecks.filter(([k, v]) => v === true).length;
const totalChecks = boolChecks.length;
const editorial_score = Math.round((passedChecks / totalChecks) * 100);

const autoPublish = prev.auto_publish === true;
const reviewRequired = prev.review_required === true;

let status;
if (editorial_score >= 80 && seoScore >= 60 && autoPublish && !reviewRequired) {
  status = 'ready';
} else if (editorial_score >= 70 && seoScore >= 40) {
  status = reviewRequired ? 'pending-review' : 'ready';
} else if (editorial_score >= 50) {
  status = 'auto-draft';
} else {
  status = 'draft';
}

const shouldAutoPromote = status === 'ready' && autoPublish && !reviewRequired;

const internalLinks = [];
const recentPostsData = prev.recent_posts_for_interlink || [];
for (const rp of recentPostsData) {
  const rpWords = (rp.title || '').toLowerCase().split(/\s+/).filter(w => w.length > 4);
  const bodyLower = body.toLowerCase();
  const matches = rpWords.filter(w => bodyLower.includes(w));
  if (matches.length >= 2) internalLinks.push('/post/' + rp.slug);
}

const slug = (title || 'sem-titulo').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').substring(0, 80) + '-' + Date.now().toString(36);

return [{
  json: {
    cluster_id: prev.cluster_id,
    fingerprint: prev.fingerprint,
    title: title || 'Sem titulo',
    subtitle: article.subtitle || null,
    slug: slug,
    excerpt: article.excerpt || null,
    body_markdown: body,
    body_html: mdToHtml(body),
    language: 'pt',
    editorial_score: editorial_score,
    confidence_score: prev.confidence_score,
    seo_score: seoScore,
    readability_score: readabilityScore,
    originality_score: originalityScore,
    primary_keyword: pk || null,
    secondary_keywords: Array.isArray(article.secondary_keywords) ? article.secondary_keywords : [],
    search_intent: article.search_intent || 'informational',
    meta_description: article.meta_description || null,
    internal_links: internalLinks,
    status: status,
    tone_profile: prev.target_tone || 'vision7',
    topic: prev.topic,
    auto_publish: autoPublish,
    review_required: reviewRequired,
    should_auto_promote: shouldAutoPromote,
    keywords: Array.isArray(prev.keywords) ? prev.keywords : [],
    source_articles: Array.isArray(prev.source_articles) ? prev.source_articles : [],
    quality_score: editorial_score / 10,
    quality_details: {
      total: editorial_score / 10,
      structure: h2Count >= 2 ? 8 : 6,
      seo_aeo: seoScore / 10,
      data_sources: sourceTitles.length >= 2 ? 8 : 6,
      links: internalLinks.length >= 1 ? 8 : 6,
      readability: readabilityScore / 10,
      tone: 8,
      passed: editorial_score >= 70
    },
    workflow_metadata: {
      wf_id: 'WF-03',
      generation_model: response?.model || 'unknown',
      generation_timestamp: new Date().toISOString(),
      review_required: reviewRequired,
      publish_ready: status === 'ready'
    },
    seo_keywords: {
      primary_keyword: pk,
      secondary_keywords: Array.isArray(article.secondary_keywords) ? article.secondary_keywords : [],
      lsi_keywords: [],
      long_tail_keywords: [],
      entities: []
    },
    cover_image_prompt: article.cover_image?.prompt || 'Dark cinematic image for ' + (prev.topic || 'tecnologia'),
    cover_image_accent: article.cover_image?.color_accent || '#0a0f1c',
    editorial_metadata: {
      category: prev.topic || 'tecnologia',
      lead: article.excerpt || '',
      conclusion: '',
      cta: '',
      portugal_section: article.portugal_section || {},
      dated_prediction: article.dated_prediction || '',
      faqs: article.faqs || [],
      toc: article.table_of_contents || []
    },
    model_info: {
      provider: response?.provider || 'unknown',
      model: response?.model || 'unknown',
      source_count: prev.source_count,
      generated_at: new Date().toISOString(),
      automation_name: prev.automation_name || null,
      automation_updated_at: prev.automation_updated_at || null,
      target_tone: prev.target_tone || 'vision7',
      custom_prompt_applied: prev.custom_prompt_applied === true,
      trend_score: prev.trend_score || 0,
      priority_rank: prev.priority_rank || 0
    },
    moderation: audit,
    skip: false,
    _mode: prev._mode || 'news',
    pending_link_id: prev.pending_link_id || null
  }
}];

const post = $('Audit + SEO Score').first().json;
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };

const body_html = post.body_html || '';
const linkRegex = /<a\s+[^>]*href="(\/[^"#?][^"]*)"[^>]*>([\s\S]*?)<\/a>/gi;
const rawLinks = [];
let m;
while ((m = linkRegex.exec(body_html)) !== null) {
  const href = m[1].trim();
  const anchor = m[2].replace(/<[^>]+>/g, '').trim();
  if (href && !rawLinks.find(l => l.href === href)) rawLinks.push({ href, anchor_text: anchor });
}

if (rawLinks.length === 0) {
  return [{ json: { ...post, link_graph: [], link_validation: { total: 0, active: 0, pending: 0, pending_slugs: [] } } }];
}

const linksWithSlugs = rawLinks.map(l => {
  const parts = l.href.split('/').filter(Boolean);
  const slug = parts[parts.length - 1] || '';
  const baseSlug = slug.replace(/-[a-z0-9]{6,}$/, '');
  return { ...l, slug, baseSlug };
});

let existingSlugs = new Set();
try {
  const baseSlugs = [...new Set(linksWithSlugs.map(l => l.baseSlug).filter(Boolean))];
  if (baseSlugs.length > 0) {
    const orFilter = baseSlugs.map(s => `slug.ilike.${s}%`).join(',');
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: SUPABASE_URL + `/rest/v1/posts?select=slug&status=eq.published&or=(${encodeURIComponent(orFilter)})&limit=100`,
      headers, json: true
    });
    if (Array.isArray(resp)) {
      for (const p of resp) {
        existingSlugs.add(p.slug);
        existingSlugs.add(p.slug.replace(/-[a-z0-9]{6,}$/, ''));
      }
    }
  }
} catch (e) { /* non-fatal */ }

const linkGraph = linksWithSlugs.map(l => ({
  href: l.href,
  slug: l.slug,
  base_slug: l.baseSlug,
  anchor_text: l.anchor_text,
  status: (existingSlugs.has(l.slug) || existingSlugs.has(l.baseSlug)) ? 'active' : 'pending'
}));

let enhancedHtml = body_html;
for (const link of linkGraph) {
  if (link.status === 'pending') {
    const escaped = link.href.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    enhancedHtml = enhancedHtml.replace(
      new RegExp(`(<a\\s(?:[^>](?!data-link-status))*href="${escaped}"(?:[^>](?!data-link-status))*)>`, 'gi'),
      (match, opening) => {
        if (match.includes('data-link-status')) return match;
        return `${opening} data-link-status="pending" title="Artigo relacionado em preparação — disponível em breve">`;
      }
    );
  }
}

const activeLinks = linkGraph.filter(l => l.status === 'active');
const pendingLinks = linkGraph.filter(l => l.status === 'pending');

return [{
  json: {
    ...post,
    body_html: enhancedHtml,
    link_graph: linkGraph,
    link_validation: {
      total: linkGraph.length,
      active: activeLinks.length,
      pending: pendingLinks.length,
      pending_slugs: pendingLinks.map(l => ({ slug: l.slug, href: l.href, anchor: l.anchor_text }))
    }
  }
}];

const post = $json;
const SUPABASE_URL = $env.SUPABASE_URL || 'https://xhpfxvoonpclonjyfimt.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;
const headers = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=representation' };
const functionHeaders = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' };

// Build model_info absorbing extra fields not in the schema
const modelInfo = {
  ...(post.model_info || {}),
  topic: post.topic || null,
  cover_image_prompt: post.cover_image_prompt || null,
  cover_image_accent: post.cover_image_accent || null,
  workflow_metadata: post.workflow_metadata || null,
  seo_keywords: post.seo_keywords || null,
  editorial_metadata: post.editorial_metadata || null
};

// Build metrics absorbing quality fields
const metrics = {
  quality_score: post.quality_score || 0,
  quality_details: post.quality_details || null
};

let saved = null;
try {
  saved = await this.helpers.httpRequest({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/curated_posts',
    headers: headers,
    body: {
      cluster_id: post.cluster_id,
      title: post.title,
      subtitle: post.subtitle,
      slug: post.slug,
      excerpt: post.excerpt,
      body_markdown: post.body_markdown,
      body_html: post.body_html,
      language: post.language,
      editorial_score: post.editorial_score,
      confidence_score: post.confidence_score,
      seo_score: post.seo_score,
      readability_score: post.readability_score,
      originality_score: post.originality_score,
      primary_keyword: post.primary_keyword,
      secondary_keywords: post.secondary_keywords,
      search_intent: post.search_intent,
      meta_description: post.meta_description,
      internal_links: post.internal_links,
      status: post.status,
      tone_profile: post.tone_profile,
      model_info: modelInfo,
      moderation: post.moderation,
      metrics: metrics
    },
    json: true
  });
} catch (e) {
  return [{ json: { error: 'Save curated failed: ' + e.message, cluster_id: post.cluster_id } }];
}

const savedEntry = Array.isArray(saved) ? saved[0] : saved;
const wantsAutoPublish = post.auto_publish === true;
const shouldAutoPromote = post.should_auto_promote === true;
let notificationResult = null;
let notificationError = null;
let autoPromotionResult = null;
let autoPromotionError = null;

if (savedEntry?.id) {
  try {
    notificationResult = await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/functions/v1/notify-curated-post',
      headers: functionHeaders,
      body: { curatedPostId: savedEntry.id, sourceArticles: Array.isArray(post.source_articles) ? post.source_articles : [] },
      json: true
    });
  } catch (e) { notificationError = e.message; }
}

if (savedEntry?.id && shouldAutoPromote) {
  try {
    autoPromotionResult = await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/functions/v1/promote-curated-post',
      headers: functionHeaders,
      body: { curatedPostId: savedEntry.id },
      json: true
    });
  } catch (e) { autoPromotionError = e.message; }
}

if (savedEntry?.id && post.cluster_id) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: SUPABASE_URL + '/rest/v1/news_clusters?id=eq.' + post.cluster_id,
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json' },
      body: { is_curated: true, curated_at: new Date().toISOString() },
      json: true
    });
  } catch (e) { /* non-fatal */ }
}

if (savedEntry?.id && Array.isArray(post.link_graph) && post.link_graph.length > 0) {
  try {
    const linkRows = post.link_graph.map(l => ({
      source_curated_id: savedEntry.id,
      target_slug: l.base_slug || l.slug,
      href: l.href,
      anchor_text: l.anchor_text || null,
      status: l.status
    }));
    await this.helpers.httpRequest({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/article_link_graph',
      headers: { ...headers, 'Prefer': 'resolution=merge-duplicates' },
      body: linkRows,
      json: true
    });
  } catch (e) { /* non-fatal */ }
}

const autoPromotionSucceeded = !autoPromotionError && ['promoted', 'duplicate', 'already_published'].includes(String(autoPromotionResult?.status || ''));
const finalStatus = autoPromotionSucceeded ? 'published' : (savedEntry?.status || post.status || 'draft');
const readyForReview = ['pending-review', 'auto-draft', 'ready'].includes(finalStatus) || (shouldAutoPromote && !autoPromotionSucceeded);

const _postMode = post._mode || 'news';
const _pendingLId = post.pending_link_id || null;
if (_postMode === 'pending' && _pendingLId && savedEntry?.id) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: SUPABASE_URL + '/rest/v1/article_link_graph?id=eq.' + _pendingLId,
      headers: { ...headers, 'Prefer': 'return=minimal' },
      body: { source_curated_id: savedEntry.id, status: 'active' },
      json: true
    });
  } catch (e) { /* non-fatal */ }
}

return [{
  json: {
    success: true,
    draft_auto: autoPromotionResult?.promoted === true,
    auto_publish_requested: wantsAutoPublish,
    auto_promotion_attempted: shouldAutoPromote,
    auto_promotion_status: autoPromotionResult?.status || null,
    auto_promotion_error: autoPromotionError,
    curation_notification_status: notificationResult?.status || null,
    curation_notification_error: notificationError,
    ready_for_review: readyForReview,
    curated_post_id: savedEntry?.id || null,
    post_id: autoPromotionResult?.postId || null,
    slug: autoPromotionResult?.slug || savedEntry?.slug || post.slug || null,
    title: post.title,
    editorial_score: post.editorial_score,
    seo_score: post.seo_score,
    readability_score: post.readability_score,
    originality_score: post.originality_score,
    primary_keyword: post.primary_keyword,
    status: finalStatus
  }
}];

